# Capability heat map — data structure and rendering logic

from dataclasses import dataclass
from typing import Literal

Intensity = Literal['Critical', 'High', 'Medium', 'Low', 'None']

@dataclass
class HeatMapCell:
    capability: str
    value_stream: str
    intensity: Intensity
    rationale: str          # Why this intensity was assigned
    shared_with: list[str]  # Other streams that need this same capability

@dataclass
class CapabilityHeatMap:
    capabilities: list[str]
    value_streams: list[str]
    cells: list[HeatMapCell]

    def shared_capabilities(self) -> list[str]:
        # Capabilities needed at Critical or High by >= 3 streams
        # These are candidates for centralized platform investment
        from collections import Counter
        counts = Counter(
            c.capability for c in self.cells
            if c.intensity in ('Critical', 'High')
        )
        return [cap for cap, n in counts.items() if n >= 3]

    def capability_investment_priority(self) -> list[tuple]:
        # Sort capabilities by total weight (Critical=4, High=3, Medium=2, Low=1)
        weights = {'Critical': 4, 'High': 3, 'Medium': 2, 'Low': 1, 'None': 0}
        totals: dict = {}
        for c in self.cells:
            totals[c.capability] = totals.get(c.capability, 0) + weights[c.intensity]
        return sorted(totals.items(), key=lambda x: x[1], reverse=True)
